module morphological_dilation (  
    input [8:0] binary_input, // 3x3 binary binary_input represented as a 9-bit input  
    output reg dilated // Output indicating dilation result  
);  
    always @* begin  
        // Check if any bit in the 3x3 matrix is 1  
        if (binary_input[0] || binary_input[1] || binary_input[2] ||  
            binary_input[3] || binary_input[4] || binary_input[5] ||  
            binary_input[6] || binary_input[7] || binary_input[8])  
            dilated = 1'b1;  
        else  
            dilated = 1'b0;  
    end  
endmodule
